class Solution {
public:
    int subarraySum(vector<int>& nums, int k) {
        unordered_map<int, int> mp;
        mp[0] = 1; // 前缀和 0 出现 1 次，兜住从下标 0 开始的子数组
        int count = 0, pre = 0;
        for (auto& x: nums) {
            pre += x;
            if (mp.find(pre - k) != mp.end()) { // 先查后存，k=0 时不会把自己算进去
                count += mp[pre - k];
            }
            mp[pre]++;
        }
        return count;
    }
};
